// PROBLEMA — botão sem label útil para VoiceOver:
Button {
    favoritar(tarefa)
} label: {
    Image(systemName: "heart")  // VoiceOver anuncia: "heart, button"
}

// SOLUÇÃO — label semântico:
Button {
    favoritar(tarefa)
} label: {
    Image(systemName: "heart")
}
.accessibilityLabel("Favoritar \(tarefa.titulo)")  // VoiceOver: "Favoritar Tarefa A, button"

// Imagem decorativa — ocultar do VoiceOver:
Image("background-pattern")
    .accessibilityHidden(true)  // VoiceOver ignora essa imagem

// Imagem informativa — adicionar descrição:
Image("grafico-vendas")
    .accessibilityLabel("Gráfico de vendas dos últimos 30 dias")

// Slider com label e valor personalizado:
Slider(value: $volume, in: 0...1)
    .accessibilityLabel("Volume")
    .accessibilityValue("\(Int(volume * 100))%")

// Toggle com label contextual:
Toggle("", isOn: $notificacoes)
    .accessibilityLabel("Notificações push")
    .accessibilityHint("Ativa ou desativa notificações do app")

// Elemento com ações customizadas:
TarefaCard(tarefa: tarefa)
    .accessibilityLabel(tarefa.titulo)
    .accessibilityValue(tarefa.concluida ? "Concluída" : "Pendente")
    .accessibilityActions {
        AccessibilityAction(named: "Concluir") {
            vm.marcarConcluida(tarefa)
        }
        AccessibilityAction(named: "Deletar") {
            vm.deletar(tarefa)
        }
    }

// Correto — text style semântico, escala com Dynamic Type:
Text("Título")
    .font(.headline)  // escala automaticamente

Text("Corpo do texto")
    .font(.body)      // escala automaticamente

// Evite — tamanho fixo não escala:
Text("Título")
    .font(.system(size: 17))  // NÃO escala com Dynamic Type

// Permite múltiplas linhas para textos longos:
Text(tarefa.titulo)
    .font(.headline)
    .lineLimit(nil)  // sem limite de linhas — respeita Dynamic Type grande
    .fixedSize(horizontal: false, vertical: true)  // expande verticalmente

// Preview em diferentes tamanhos:
#Preview {
    TarefaCard(tarefa: .preview)
        .environment(\.sizeCategory, .accessibilityExtraExtraLarge)
}

// Agrupar elementos de uma célula:
HStack {
    Image(systemName: tarefa.icone)
    VStack(alignment: .leading) {
        Text(tarefa.titulo).font(.headline)
        Text(tarefa.subtitulo).font(.caption)
    }
}
.accessibilityElement(children: .combine)  // VoiceOver lê tudo junto
// VoiceOver anuncia: "[ícone], [título], [subtítulo], button"
